const REPOS = [
  { repo: 'squidgy_updated_ui', owner: 'Squidgy-AI', docFile: 'squidgy_updated_ui/brownfield-architecture.md' },
  { repo: 'squidgy_updated_backend', owner: 'Squidgy-AI', docFile: 'squidgy_updated_backend/brownfield-architecture.md' }
];

const FILE_TO_SECTION_MAP = {
  'squidgy_updated_ui': {
    'agents/configs/': ['The Agent System'],
    'client/components/': ['UI Component System', 'Source Tree and Module Organization'],
    'client/services/': ['Client Services Reference'],
    'client/hooks/': ['Custom Hooks'],
    'client/pages/': ['Source Tree and Module Organization'],
    'server/': ['Server API Routes'],
    'server/routes/': ['Server API Routes'],
    'database/': ['Database Schema'],
    'shared/': ['Client Services Reference'],
    'knowledge_base/': ['The Agent System'],
    'package.json': ['Tech Stack'],
    'vite.config': ['Build and Deployment'],
    'tsconfig': ['Build and Deployment'],
    '.env': ['Quick Reference']
  },
  'squidgy_updated_backend': {
    'main.py': ['API Endpoints', 'Core Business Logic', 'In-Memory State'],
    'routes/': ['API Endpoints'],
    'requirements.txt': ['Tech Stack'],
    'Procfile': ['Deployment'],
    'runtime.txt': ['Deployment'],
    'scripts/': ['Source Tree and Module Organization'],
    'migrations/': ['Databases'],
    'Tools/': ['Source Tree and Module Organization']
  }
};

return [{ json: { repos: REPOS, fileMap: FILE_TO_SECTION_MAP } }];

const content = $input.first().json;
let lastRunData;

try {
  // GitHub API returns content as base64
  const decoded = Buffer.from(content.content, 'base64').toString('utf8');
  lastRunData = JSON.parse(decoded);
} catch (e) {
  // First run or corrupted data - use empty SHAs
  lastRunData = { repos: {} };
}

const repos = $('Code - Initialize').first().json.repos;
const items = repos.map(r => ({
  json: {
    ...r,
    lastSHA: lastRunData.repos?.[r.repo]?.lastSHA || '',
    fileMap: $('Code - Initialize').first().json.fileMap
  }
}));

return items;

const input = $input.first().json;
const repo = $('Loop Over Repos').first().json.repo;
const docFile = $('Loop Over Repos').first().json.docFile;
const fileMap = $('Loop Over Repos').first().json.fileMap;
const repoMap = fileMap[repo] || {};

// Get compare data
const compareData = input;
const files = compareData.files || [];
const newSHA = compareData.commits?.length > 0 
  ? compareData.commits[compareData.commits.length - 1].sha 
  : $('Loop Over Repos').first().json.lastSHA;

// Map changed files to doc sections
const sectionsToUpdate = new Map();

for (const file of files) {
  const filename = file.filename;
  for (const [pattern, sections] of Object.entries(repoMap)) {
    if (filename.includes(pattern) || filename.startsWith(pattern)) {
      for (const section of sections) {
        if (!sectionsToUpdate.has(section)) {
          sectionsToUpdate.set(section, {
            section,
            changedFiles: [],
            patches: []
          });
        }
        const entry = sectionsToUpdate.get(section);
        if (!entry.changedFiles.includes(filename)) {
          entry.changedFiles.push(filename);
          entry.patches.push({
            filename,
            status: file.status,
            patch: (file.patch || '').substring(0, 2000) // Limit patch size
          });
        }
      }
    }
  }
}

const sectionItems = Array.from(sectionsToUpdate.values()).map(s => ({
  json: {
    ...s,
    repo,
    docFile,
    newSHA
  }
}));

if (sectionItems.length === 0) {
  return [{ json: { repo, docFile, newSHA, noChanges: true } }];
}

return sectionItems;

const section = $('Loop Over Sections').first().json;
const docContent = $input.first().json;

// Decode doc from base64
let fullDoc;
try {
  fullDoc = Buffer.from(docContent.content, 'base64').toString('utf8');
} catch(e) {
  fullDoc = '';
}

// Extract the target section from the doc
const sectionName = section.section;
const lines = fullDoc.split('\n');
let sectionStart = -1;
let sectionEnd = lines.length;
let sectionLevel = 0;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  const headingMatch = line.match(/^(#{1,4})\s+(.+)/);
  if (headingMatch) {
    const level = headingMatch[1].length;
    const title = headingMatch[2].trim();
    if (title.includes(sectionName) || sectionName.includes(title.replace(/^\d+\.\s*/, ''))) {
      sectionStart = i;
      sectionLevel = level;
    } else if (sectionStart >= 0 && level <= sectionLevel) {
      sectionEnd = i;
      break;
    }
  }
}

const currentSection = sectionStart >= 0 
  ? lines.slice(sectionStart, sectionEnd).join('\n')
  : `Section "${sectionName}" not found in document.`;

// Build patches summary
const patchesSummary = section.patches.map(p => 
  `### ${p.filename} (${p.status})\n\`\`\`diff\n${p.patch}\n\`\`\``
).join('\n\n');

const prompt = `You are a technical documentation updater for the Squidgy AI platform.

TASK: Update the following documentation section based on recent code changes. 
- Only modify content that is directly affected by the changes shown below.
- Maintain the EXACT same markdown heading level and formatting style.
- Keep the same overall structure. Add new items if new files/features were added. Remove items if files were deleted.
- Be factual and precise. Don't add speculative content.
- Return ONLY the updated section markdown, starting with the section heading.

CURRENT DOCUMENTATION SECTION:
${currentSection}

CODE CHANGES (diffs from ${section.repo}):
${patchesSummary}

FILES CHANGED: ${section.changedFiles.join(', ')}

Return the updated section as valid markdown. If no meaningful documentation changes are needed (e.g., whitespace-only code changes), return the section unchanged.`;

return [{
  json: {
    aiPrompt: prompt,
    sectionName,
    sectionStart,
    sectionEnd,
    fullDoc,
    repo: section.repo,
    docFile: section.docFile,
    newSHA: section.newSHA,
    changedFiles: section.changedFiles
  }
}];

