const input = $input.first().json;
const output = input.output;

const fullDoc = $('Code - Build AI Prompt').first().json.fullDoc;
const sectionStart = $('Code - Build AI Prompt').first().json.sectionStart;
const sectionEnd = $('Code - Build AI Prompt').first().json.sectionEnd;
const sectionName = $('Code - Build AI Prompt').first().json.sectionName;
const repo = $('Code - Build AI Prompt').first().json.repo;
const docFile = $('Code - Build AI Prompt').first().json.docFile;
const newSHA = $('Code - Build AI Prompt').first().json.newSHA;
const changedFiles = $('Code - Build AI Prompt').first().json.changedFiles;

let updatedMarkdown;
try {
  updatedMarkdown = output.updatedMarkdown || output.response || '';
} catch(e) {
  updatedMarkdown = '';
}

const changeDescription = output?.changeDescription || `Updated ${sectionName}`;

if (!updatedMarkdown || sectionStart < 0) {
  // No update needed or section not found - pass through unchanged
  return [{ json: { 
    markdown: fullDoc, 
    fileName: docFile.split('/').pop(),
    filePath: docFile,
    commitMessage: `No changes needed for ${sectionName} in ${docFile}`,
    repo,
    newSHA,
    skipped: true
  }}];
}

const lines = fullDoc.split('\n');
const before = lines.slice(0, sectionStart);
const after = lines.slice(sectionEnd);
const reconstructed = [...before, updatedMarkdown.trim(), '', ...after].join('\n');

return [{
  json: {
    markdown: reconstructed,
    fileName: docFile.split('/').pop(),
    filePath: docFile,
    commitMessage: `Auto-update ${sectionName}: ${changeDescription} [${changedFiles.slice(0,3).join(', ')}]`,
    repo,
    newSHA,
    skipped: false
  }
}];

const markdown = $json.markdown;
const buffer = Buffer.from(markdown, 'utf8');
return [{
  json: { filePath: $json.filePath, commitMessage: $json.commitMessage, skipped: $json.skipped },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: $json.fileName
    }
  }
}];

// Collect all newSHAs from processed repos
const repos = $('Code - Initialize').first().json.repos;
const lastRunData = {
  lastRun: new Date().toISOString(),
  repos: {}
};

// For each repo, get the latest SHA we processed
for (const repo of repos) {
  // Try to find the newSHA from processing
  try {
    const items = $('Code - Extract Changes').all();
    const repoItem = items.find(i => i.json.repo === repo.repo);
    if (repoItem?.json.newSHA) {
      lastRunData.repos[repo.repo] = {
        lastSHA: repoItem.json.newSHA,
        owner: repo.owner
      };
    } else {
      // Fallback - keep old SHA
      const oldData = $('Code - Parse Last Run').all().find(i => i.json.repo === repo.repo);
      lastRunData.repos[repo.repo] = {
        lastSHA: oldData?.json.lastSHA || '',
        owner: repo.owner
      };
    }
  } catch(e) {
    lastRunData.repos[repo.repo] = { lastSHA: '', owner: repo.owner };
  }
}

return [{
  json: {
    content: JSON.stringify(lastRunData, null, 2),
    fileName: '.last-run.json',
    filePath: '.last-run.json'
  }
}];

const content = $json.content;
const buffer = Buffer.from(content, 'utf8');
return [{
  json: { filePath: $json.filePath },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/json',
      fileName: $json.fileName
    }
  }
}];
